    def get_provisioning_uri(self, secret, user_id, issuer_name):
        """
        Generates a provisioning URI (otpauth://) for a TOTP secret.
        This URI can be used to generate a QR code for authenticator apps.
        """
        label = f"{quote(issuer_name)}:{quote(user_id)}"
        params = {
            'secret': secret,
            'issuer': issuer_name,
            'algorithm': self.hash_function,
            'digits': self.digits,
            'period': self.time_step
        }
        query_string = urlencode(params)
        return f"otpauth://totp/{label}?{query_string}"

    def generate_qr_code(self, provisioning_uri, filename=None):
        """
        Generates a QR code image from a provisioning URI.
        If filename is provided, saves the QR code to a file.
        Otherwise, returns a PIL Image object.
        """
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(provisioning_uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")

        if filename:
            img.save(filename)
            return f"QR code saved to {filename}"
        else:
            return img

